package com.payment.module.security

import android.content.Context
import android.content.pm.PackageManager
import android.os.Build
import android.provider.Settings
import java.io.File

class IntegrityChecker(private val context: Context) {

    fun isDeviceSecure(): SecurityCheckResult {
        val issues = mutableListOf<String>()

        if (isDeviceRooted()) {
            issues.add("Device appears to be rooted")
        }

        if (isRunningOnEmulator()) {
            issues.add("Running on emulator")
        }

        if (isDebuggable()) {
            issues.add("App is debuggable")
        }

        if (!isScreenLockEnabled()) {
            issues.add("No screen lock enabled")
        }

        if (isHookingFrameworkDetected()) {
            issues.add("Hooking framework detected")
        }

        return SecurityCheckResult(
            isSecure = issues.isEmpty(),
            issues = issues,
            riskLevel = when {
                issues.isEmpty() -> RiskLevel.LOW
                issues.size <= 1 -> RiskLevel.MEDIUM
                else -> RiskLevel.HIGH
            }
        )
    }

    private fun isDeviceRooted(): Boolean {
        val rootPaths = arrayOf(
            "/system/app/Superuser.apk",
            "/sbin/su",
            "/system/bin/su",
            "/system/xbin/su",
            "/data/local/xbin/su",
            "/data/local/bin/su",
            "/system/sd/xbin/su",
            "/system/bin/failsafe/su",
            "/data/local/su"
        )

        for (path in rootPaths) {
            if (File(path).exists()) return true
        }

        return try {
            val process = Runtime.getRuntime().exec(arrayOf("which", "su"))
            process.inputStream.bufferedReader().readLine() != null
        } catch (e: Exception) {
            false
        }
    }

    private fun isRunningOnEmulator(): Boolean {
        return (Build.FINGERPRINT.startsWith("generic")
                || Build.FINGERPRINT.startsWith("unknown")
                || Build.MODEL.contains("google_sdk")
                || Build.MODEL.contains("Emulator")
                || Build.MODEL.contains("Android SDK built for x86")
                || Build.MANUFACTURER.contains("Genymotion")
                || Build.BRAND.startsWith("generic") && Build.DEVICE.startsWith("generic")
                || "google_sdk" == Build.PRODUCT)
    }

    private fun isDebuggable(): Boolean {
        return (context.applicationInfo.flags and android.content.pm.ApplicationInfo.FLAG_DEBUGGABLE) != 0
    }

    private fun isScreenLockEnabled(): Boolean {
        return try {
            val lockEnabled = Settings.Secure.getInt(
                context.contentResolver,
                Settings.Secure.LOCK_PATTERN_ENABLED,
                0
            )
            lockEnabled == 1 || isKeyguardSecure()
        } catch (e: Exception) {
            isKeyguardSecure()
        }
    }

    private fun isKeyguardSecure(): Boolean {
        val keyguardManager = context.getSystemService(Context.KEYGUARD_SERVICE)
                as android.app.KeyguardManager
        return keyguardManager.isKeyguardSecure
    }

    private fun isHookingFrameworkDetected(): Boolean {
        val suspiciousPackages = arrayOf(
            "de.robv.android.xposed",
            "de.robv.android.xposed.installer",
            "com.saurik.substrate",
            "io.va.exposed"
        )

        val pm = context.packageManager
        for (pkg in suspiciousPackages) {
            try {
                pm.getPackageInfo(pkg, PackageManager.GET_ACTIVITIES)
                return true
            } catch (e: PackageManager.NameNotFoundException) {
                // Not found, continue
            }
        }

        // Check for Xposed in stack trace
        try {
            throw Exception("Detection check")
        } catch (e: Exception) {
            for (element in e.stackTrace) {
                if (element.className.contains("xposed", ignoreCase = true)) {
                    return true
                }
            }
        }

        return false
    }

    data class SecurityCheckResult(
        val isSecure: Boolean,
        val issues: List<String>,
        val riskLevel: RiskLevel
    )

    enum class RiskLevel {
        LOW, MEDIUM, HIGH
    }
}

