package com.payment.module.security

object DataMasker {
    fun maskCardNumber(cardNumber: String): String {
        val cleaned = cardNumber.replace("\\s".toRegex(), "")
        if (cleaned.length < 4) return "****"
        return "**** **** **** ${cleaned.takeLast(4)}"
    }

    fun maskEmail(email: String): String {
        val parts = email.split("@")
        if (parts.size != 2) return "***@***"
        val name = parts[0]
        val domain = parts[1]
        val maskedName = if (name.length > 2) {
            "${name.first()}${"*".repeat(name.length - 2)}${name.last()}"
        } else {
            "*".repeat(name.length)
        }
        return "$maskedName@$domain"
    }

    fun maskAmount(amount: String): String {
        return "***.**"
    }

    fun maskPhoneNumber(phone: String): String {
        val cleaned = phone.replace("[^0-9+]".toRegex(), "")
        if (cleaned.length < 4) return "****"
        return "${"*".repeat(cleaned.length - 4)}${cleaned.takeLast(4)}"
    }
}

