package com.payment.module.network

import android.content.Context
import okhttp3.CertificatePinner
import okhttp3.Interceptor
import okhttp3.OkHttpClient
import okhttp3.logging.HttpLoggingInterceptor
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import java.util.concurrent.TimeUnit

object NetworkModule {

    private const val BASE_URL = "https://api.yourpaymentserver.com/"
    private const val CONNECTION_TIMEOUT = 30L
    private const val READ_TIMEOUT = 30L
    private const val WRITE_TIMEOUT = 30L

    // Replace with your actual certificate pins
    private val certificatePinner = CertificatePinner.Builder()
        .add("api.yourpaymentserver.com", "sha256/AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA=")
        .add("api.yourpaymentserver.com", "sha256/BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB=")
        .build()

    fun createApiService(context: Context, authTokenProvider: () -> String?): PaymentApiService {
        val client = createOkHttpClient(context, authTokenProvider)
        val retrofit = Retrofit.Builder()
            .baseUrl(BASE_URL)
            .client(client)
            .addConverterFactory(GsonConverterFactory.create())
            .build()
        return retrofit.create(PaymentApiService::class.java)
    }

    private fun createOkHttpClient(context: Context, authTokenProvider: () -> String?): OkHttpClient {
        return OkHttpClient.Builder()
            .connectTimeout(CONNECTION_TIMEOUT, TimeUnit.SECONDS)
            .readTimeout(READ_TIMEOUT, TimeUnit.SECONDS)
            .writeTimeout(WRITE_TIMEOUT, TimeUnit.SECONDS)
            .certificatePinner(certificatePinner)
            .addInterceptor(createAuthInterceptor(authTokenProvider))
            .addInterceptor(createSecurityHeadersInterceptor())
            .addInterceptor(createLoggingInterceptor())
            .build()
    }

    private fun createAuthInterceptor(authTokenProvider: () -> String?): Interceptor {
        return Interceptor { chain ->
            val originalRequest = chain.request()
            val token = authTokenProvider()
            val request = if (token != null) {
                originalRequest.newBuilder()
                    .header("Authorization", "Bearer $token")
                    .build()
            } else {
                originalRequest
            }
            chain.proceed(request)
        }
    }

    private fun createSecurityHeadersInterceptor(): Interceptor {
        return Interceptor { chain ->
            val request = chain.request().newBuilder()
                .header("X-Request-ID", java.util.UUID.randomUUID().toString())
                .header("X-Client-Version", "1.0.0")
                .header("X-Platform", "Android")
                .header("Content-Type", "application/json")
                .build()
            chain.proceed(request)
        }
    }

    private fun createLoggingInterceptor(): HttpLoggingInterceptor {
        return HttpLoggingInterceptor().apply {
            // Only log headers in debug, never log body (contains sensitive data)
            level = if (android.os.Build.TYPE == "userdebug") {
                HttpLoggingInterceptor.Level.HEADERS
            } else {
                HttpLoggingInterceptor.Level.NONE
            }
            redactHeader("Authorization")
            redactHeader("Cookie")
        }
    }
}

