package com.payment.module.billing

import android.app.Activity
import android.content.Context
import com.android.billingclient.api.*
import com.payment.module.data.model.Product
import com.payment.module.data.model.ProductType
import kotlinx.coroutines.channels.Channel
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.suspendCancellableCoroutine
import java.math.BigDecimal
import kotlin.coroutines.resume

class BillingManager(private val context: Context) : PurchasesUpdatedListener {

    private var billingClient: BillingClient? = null
    private val _connectionState = MutableStateFlow(BillingConnectionState.DISCONNECTED)
    val connectionState: StateFlow<BillingConnectionState> = _connectionState.asStateFlow()

    val purchaseChannel = Channel<PurchaseUpdate>(Channel.BUFFERED)

    enum class BillingConnectionState {
        DISCONNECTED, CONNECTING, CONNECTED, CONNECTION_FAILED
    }

    data class PurchaseUpdate(
        val purchases: List<Purchase>?,
        val responseCode: Int
    )

    fun initialize() {
        billingClient = BillingClient.newBuilder(context)
            .setListener(this)
            .enablePendingPurchases()
            .build()
    }

    suspend fun connect(): Boolean = suspendCancellableCoroutine { continuation ->
        _connectionState.value = BillingConnectionState.CONNECTING
        billingClient?.startConnection(object : BillingClientStateListener {
            override fun onBillingSetupFinished(result: BillingResult) {
                if (result.responseCode == BillingClient.BillingResponseCode.OK) {
                    _connectionState.value = BillingConnectionState.CONNECTED
                    if (continuation.isActive) continuation.resume(true)
                } else {
                    _connectionState.value = BillingConnectionState.CONNECTION_FAILED
                    if (continuation.isActive) continuation.resume(false)
                }
            }

            override fun onBillingServiceDisconnected() {
                _connectionState.value = BillingConnectionState.DISCONNECTED
            }
        })
    }

    suspend fun queryProducts(productIds: List<String>, type: String = BillingClient.ProductType.INAPP): List<ProductDetails> {
        val productList = productIds.map { productId ->
            QueryProductDetailsParams.Product.newBuilder()
                .setProductId(productId)
                .setProductType(type)
                .build()
        }

        val params = QueryProductDetailsParams.newBuilder()
            .setProductList(productList)
            .build()

        return suspendCancellableCoroutine { continuation ->
            billingClient?.queryProductDetailsAsync(params) { result, productDetailsList ->
                if (result.responseCode == BillingClient.BillingResponseCode.OK) {
                    if (continuation.isActive) continuation.resume(productDetailsList)
                } else {
                    if (continuation.isActive) continuation.resume(emptyList())
                }
            }
        }
    }

    fun launchPurchaseFlow(activity: Activity, productDetails: ProductDetails): BillingResult? {
        val offerToken = productDetails.subscriptionOfferDetails?.firstOrNull()?.offerToken

        val productDetailsParamsBuilder = BillingFlowParams.ProductDetailsParams.newBuilder()
            .setProductDetails(productDetails)

        if (offerToken != null) {
            productDetailsParamsBuilder.setOfferToken(offerToken)
        }

        val billingFlowParams = BillingFlowParams.newBuilder()
            .setProductDetailsParamsList(listOf(productDetailsParamsBuilder.build()))
            .build()

        return billingClient?.launchBillingFlow(activity, billingFlowParams)
    }

    override fun onPurchasesUpdated(result: BillingResult, purchases: MutableList<Purchase>?) {
        purchaseChannel.trySend(PurchaseUpdate(purchases, result.responseCode))
    }

    suspend fun acknowledgePurchase(purchaseToken: String): Boolean {
        val params = AcknowledgePurchaseParams.newBuilder()
            .setPurchaseToken(purchaseToken)
            .build()

        return suspendCancellableCoroutine { continuation ->
            billingClient?.acknowledgePurchase(params) { result ->
                if (continuation.isActive) {
                    continuation.resume(result.responseCode == BillingClient.BillingResponseCode.OK)
                }
            }
        }
    }

    suspend fun consumePurchase(purchaseToken: String): Boolean {
        val params = ConsumeParams.newBuilder()
            .setPurchaseToken(purchaseToken)
            .build()

        return suspendCancellableCoroutine { continuation ->
            billingClient?.consumeAsync(params) { result, _ ->
                if (continuation.isActive) {
                    continuation.resume(result.responseCode == BillingClient.BillingResponseCode.OK)
                }
            }
        }
    }

    suspend fun queryPurchases(type: String = BillingClient.ProductType.INAPP): List<Purchase> {
        val params = QueryPurchasesParams.newBuilder()
            .setProductType(type)
            .build()

        return suspendCancellableCoroutine { continuation ->
            billingClient?.queryPurchasesAsync(params) { result, purchases ->
                if (result.responseCode == BillingClient.BillingResponseCode.OK) {
                    if (continuation.isActive) continuation.resume(purchases)
                } else {
                    if (continuation.isActive) continuation.resume(emptyList())
                }
            }
        }
    }

    fun mapToProduct(productDetails: ProductDetails): Product {
        val oneTimePurchaseOfferDetails = productDetails.oneTimePurchaseOfferDetails
        val price = oneTimePurchaseOfferDetails?.priceAmountMicros?.let {
            BigDecimal(it).divide(BigDecimal(1_000_000))
        } ?: BigDecimal.ZERO
        val currency = oneTimePurchaseOfferDetails?.priceCurrencyCode ?: "USD"

        return Product(
            productId = productDetails.productId,
            name = productDetails.name,
            description = productDetails.description,
            price = price,
            currency = currency,
            type = if (productDetails.productType == BillingClient.ProductType.SUBS) {
                ProductType.SUBSCRIPTION
            } else {
                ProductType.ONE_TIME
            }
        )
    }

    fun disconnect() {
        billingClient?.endConnection()
        _connectionState.value = BillingConnectionState.DISCONNECTED
    }
}

