package com.payment.module.wallet

import com.payment.module.data.model.*
import com.payment.module.network.*
import com.payment.module.security.SecureDataManager
import java.math.BigDecimal

sealed class WalletResult<out T> {
    data class Success<T>(val data: T) : WalletResult<T>()
    data class Error(val message: String, val code: String? = null) : WalletResult<Nothing>()
}

class WalletManager(
    private val apiService: PaymentApiService,
    private val secureDataManager: SecureDataManager
) {

    suspend fun getBalance(): WalletResult<WalletBalance> {
        return try {
            val response = apiService.getWalletBalance()
            if (response.isSuccessful && response.body() != null) {
                val balance = response.body()!!
                // Cache encrypted balance locally
                secureDataManager.storeSecurely(
                    "cached_balance",
                    secureDataManager.encrypt("${balance.balance}|${balance.currency}|${balance.lastUpdated}")
                )
                WalletResult.Success(balance)
            } else {
                WalletResult.Error(
                    message = "Failed to fetch balance",
                    code = response.code().toString()
                )
            }
        } catch (e: Exception) {
            WalletResult.Error(message = e.message ?: "Network error")
        }
    }

    suspend fun creditWallet(
        amount: BigDecimal,
        currency: String,
        source: String
    ): WalletResult<WalletTransactionResponse> {
        return try {
            val nonce = secureDataManager.generateNonce()
            val request = WalletCreditRequest(
                amount = amount.toPlainString(),
                currency = currency,
                source = source,
                nonce = nonce
            )
            val response = apiService.creditWallet(request)
            if (response.isSuccessful && response.body() != null) {
                WalletResult.Success(response.body()!!)
            } else {
                WalletResult.Error(
                    message = "Credit failed",
                    code = response.code().toString()
                )
            }
        } catch (e: Exception) {
            WalletResult.Error(message = e.message ?: "Network error")
        }
    }

    suspend fun debitWallet(
        amount: BigDecimal,
        currency: String,
        description: String
    ): WalletResult<WalletTransactionResponse> {
        return try {
            val nonce = secureDataManager.generateNonce()
            val request = WalletDebitRequest(
                amount = amount.toPlainString(),
                currency = currency,
                description = description,
                nonce = nonce
            )
            val response = apiService.debitWallet(request)
            if (response.isSuccessful && response.body() != null) {
                WalletResult.Success(response.body()!!)
            } else {
                WalletResult.Error(
                    message = "Debit failed",
                    code = response.code().toString()
                )
            }
        } catch (e: Exception) {
            WalletResult.Error(message = e.message ?: "Network error")
        }
    }

    suspend fun transferFunds(
        amount: BigDecimal,
        currency: String,
        recipientId: String,
        description: String
    ): WalletResult<WalletTransactionResponse> {
        return try {
            val nonce = secureDataManager.generateNonce()
            val request = WalletTransferRequest(
                amount = amount.toPlainString(),
                currency = currency,
                recipientId = recipientId,
                description = description,
                nonce = nonce
            )
            val response = apiService.transferFunds(request)
            if (response.isSuccessful && response.body() != null) {
                WalletResult.Success(response.body()!!)
            } else {
                WalletResult.Error(
                    message = "Transfer failed",
                    code = response.code().toString()
                )
            }
        } catch (e: Exception) {
            WalletResult.Error(message = e.message ?: "Network error")
        }
    }

    suspend fun getTransactionHistory(
        page: Int = 1,
        limit: Int = 20
    ): WalletResult<TransactionHistoryResponse> {
        return try {
            val response = apiService.getTransactionHistory(page, limit)
            if (response.isSuccessful && response.body() != null) {
                WalletResult.Success(response.body()!!)
            } else {
                WalletResult.Error(
                    message = "Failed to fetch history",
                    code = response.code().toString()
                )
            }
        } catch (e: Exception) {
            WalletResult.Error(message = e.message ?: "Network error")
        }
    }
}

