package com.payment.module.payment

import android.app.Activity
import com.android.billingclient.api.BillingClient
import com.android.billingclient.api.Purchase
import com.payment.module.billing.BillingManager
import com.payment.module.data.model.*
import com.payment.module.network.*
import com.payment.module.security.IntegrityChecker
import com.payment.module.security.SecureDataManager
import com.payment.module.wallet.WalletManager
import com.payment.module.wallet.WalletResult
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import java.math.BigDecimal

sealed class PaymentState {
    object Idle : PaymentState()
    object Processing : PaymentState()
    data class Success(val result: PaymentResult) : PaymentState()
    data class Error(val message: String, val errorCode: String? = null) : PaymentState()
    data class SecurityWarning(val message: String, val riskLevel: IntegrityChecker.RiskLevel) : PaymentState()
}

class PaymentProcessor(
    private val billingManager: BillingManager,
    private val walletManager: WalletManager,
    private val apiService: PaymentApiService,
    private val secureDataManager: SecureDataManager,
    private val integrityChecker: IntegrityChecker
) {
    private val _paymentState = MutableStateFlow<PaymentState>(PaymentState.Idle)
    val paymentState: StateFlow<PaymentState> = _paymentState.asStateFlow()

    suspend fun initialize(): Boolean {
        val securityResult = integrityChecker.isDeviceSecure()
        if (securityResult.riskLevel == IntegrityChecker.RiskLevel.HIGH) {
            _paymentState.value = PaymentState.SecurityWarning(
                message = "Security concerns detected: ${securityResult.issues.joinToString(", ")}",
                riskLevel = securityResult.riskLevel
            )
            // Still allow initialization but warn
        }

        billingManager.initialize()
        return billingManager.connect()
    }

    suspend fun purchaseProduct(
        activity: Activity,
        productId: String,
        productType: String = BillingClient.ProductType.INAPP
    ): PaymentResult {
        _paymentState.value = PaymentState.Processing

        // Pre-flight security check
        val securityResult = integrityChecker.isDeviceSecure()
        if (securityResult.riskLevel == IntegrityChecker.RiskLevel.HIGH) {
            val result = PaymentResult(
                success = false,
                transactionId = null,
                message = "Transaction blocked due to security concerns",
                errorCode = "SECURITY_RISK"
            )
            _paymentState.value = PaymentState.Error(result.message, result.errorCode)
            return result
        }

        try {
            // Query product details
            val productDetails = billingManager.queryProducts(listOf(productId), productType)
            val product = productDetails.firstOrNull()

            if (product == null) {
                val result = PaymentResult(
                    success = false,
                    transactionId = null,
                    message = "Product not found",
                    errorCode = "PRODUCT_NOT_FOUND"
                )
                _paymentState.value = PaymentState.Error(result.message, result.errorCode)
                return result
            }

            // Initiate payment on server
            val nonce = secureDataManager.generateNonce()
            val mappedProduct = billingManager.mapToProduct(product)

            val initiateResponse = apiService.initiatePayment(
                InitiatePaymentRequest(
                    amount = mappedProduct.price.toPlainString(),
                    currency = mappedProduct.currency,
                    paymentMethod = PaymentMethod.GOOGLE_PLAY.name,
                    productId = productId,
                    nonce = nonce
                )
            )

            if (!initiateResponse.isSuccessful) {
                val result = PaymentResult(
                    success = false,
                    transactionId = null,
                    message = "Failed to initiate payment",
                    errorCode = "INITIATION_FAILED"
                )
                _paymentState.value = PaymentState.Error(result.message, result.errorCode)
                return result
            }

            val serverTransaction = initiateResponse.body()!!

            // Launch billing flow
            val billingResult = billingManager.launchPurchaseFlow(activity, product)
            if (billingResult?.responseCode != BillingClient.BillingResponseCode.OK) {
                val result = PaymentResult(
                    success = false,
                    transactionId = serverTransaction.transactionId,
                    message = "Billing flow failed",
                    errorCode = "BILLING_FLOW_ERROR"
                )
                _paymentState.value = PaymentState.Error(result.message, result.errorCode)
                return result
            }

            // Wait for purchase update
            val purchaseUpdate = billingManager.purchaseChannel.receive()
            return handlePurchaseUpdate(purchaseUpdate, serverTransaction.transactionId)

        } catch (e: Exception) {
            val result = PaymentResult(
                success = false,
                transactionId = null,
                message = e.message ?: "Unknown error",
                errorCode = "EXCEPTION"
            )
            _paymentState.value = PaymentState.Error(result.message, result.errorCode)
            return result
        }
    }

    private suspend fun handlePurchaseUpdate(
        purchaseUpdate: BillingManager.PurchaseUpdate,
        serverTransactionId: String
    ): PaymentResult {
        if (purchaseUpdate.responseCode == BillingClient.BillingResponseCode.OK &&
            purchaseUpdate.purchases != null
        ) {
            for (purchase in purchaseUpdate.purchases) {
                if (purchase.purchaseState == Purchase.PurchaseState.PURCHASED) {
                    // Verify with server
                    val verified = verifyPurchaseWithServer(
                        serverTransactionId,
                        purchase.purchaseToken,
                        purchase.signature
                    )

                    if (verified) {
                        // Acknowledge or consume
                        val acknowledged = billingManager.acknowledgePurchase(purchase.purchaseToken)
                        if (acknowledged) {
                            val result = PaymentResult(
                                success = true,
                                transactionId = serverTransactionId,
                                message = "Purchase successful"
                            )
                            _paymentState.value = PaymentState.Success(result)
                            return result
                        }
                    }
                }
            }
        }

        val result = when (purchaseUpdate.responseCode) {
            BillingClient.BillingResponseCode.USER_CANCELED -> PaymentResult(
                success = false,
                transactionId = serverTransactionId,
                message = "Purchase cancelled by user",
                errorCode = "USER_CANCELLED"
            )
            BillingClient.BillingResponseCode.ITEM_ALREADY_OWNED -> PaymentResult(
                success = false,
                transactionId = serverTransactionId,
                message = "Item already owned",
                errorCode = "ALREADY_OWNED"
            )
            else -> PaymentResult(
                success = false,
                transactionId = serverTransactionId,
                message = "Purchase failed",
                errorCode = "PURCHASE_FAILED"
            )
        }

        _paymentState.value = PaymentState.Error(result.message, result.errorCode)
        return result
    }

    private suspend fun verifyPurchaseWithServer(
        transactionId: String,
        purchaseToken: String,
        signature: String
    ): Boolean {
        return try {
            val nonce = secureDataManager.generateNonce()
            val response = apiService.verifyPayment(
                VerifyPaymentRequest(
                    transactionId = transactionId,
                    purchaseToken = purchaseToken,
                    signature = signature,
                    nonce = nonce
                )
            )
            response.isSuccessful && response.body()?.verified == true
        } catch (e: Exception) {
            false
        }
    }

    suspend fun payWithWallet(
        amount: BigDecimal,
        currency: String,
        description: String
    ): PaymentResult {
        _paymentState.value = PaymentState.Processing

        val securityResult = integrityChecker.isDeviceSecure()
        if (securityResult.riskLevel == IntegrityChecker.RiskLevel.HIGH) {
            val result = PaymentResult(
                success = false,
                transactionId = null,
                message = "Transaction blocked due to security concerns",
                errorCode = "SECURITY_RISK"
            )
            _paymentState.value = PaymentState.Error(result.message, result.errorCode)
            return result
        }

        return when (val walletResult = walletManager.debitWallet(amount, currency, description)) {
            is WalletResult.Success -> {
                val result = PaymentResult(
                    success = walletResult.data.success,
                    transactionId = walletResult.data.transactionId,
                    message = walletResult.data.message
                )
                _paymentState.value = if (result.success) {
                    PaymentState.Success(result)
                } else {
                    PaymentState.Error(result.message)
                }
                result
            }
            is WalletResult.Error -> {
                val result = PaymentResult(
                    success = false,
                    transactionId = null,
                    message = walletResult.message,
                    errorCode = walletResult.code
                )
                _paymentState.value = PaymentState.Error(result.message, result.errorCode)
                result
            }
        }
    }

    suspend fun requestRefund(transactionId: String, reason: String, amount: BigDecimal? = null): PaymentResult {
        _paymentState.value = PaymentState.Processing

        return try {
            val nonce = secureDataManager.generateNonce()
            val response = apiService.requestRefund(
                RefundRequest(
                    transactionId = transactionId,
                    amount = amount?.toPlainString(),
                    reason = reason,
                    nonce = nonce
                )
            )

            if (response.isSuccessful && response.body() != null) {
                val refundResponse = response.body()!!
                val result = PaymentResult(
                    success = refundResponse.success,
                    transactionId = refundResponse.refundId,
                    message = refundResponse.message
                )
                _paymentState.value = if (result.success) {
                    PaymentState.Success(result)
                } else {
                    PaymentState.Error(result.message)
                }
                result
            } else {
                val result = PaymentResult(
                    success = false,
                    transactionId = null,
                    message = "Refund request failed",
                    errorCode = "REFUND_FAILED"
                )
                _paymentState.value = PaymentState.Error(result.message, result.errorCode)
                result
            }
        } catch (e: Exception) {
            val result = PaymentResult(
                success = false,
                transactionId = null,
                message = e.message ?: "Refund error",
                errorCode = "EXCEPTION"
            )
            _paymentState.value = PaymentState.Error(result.message, result.errorCode)
            result
        }
    }

    suspend fun restorePurchases(): List<Purchase> {
        val inAppPurchases = billingManager.queryPurchases(BillingClient.ProductType.INAPP)
        val subPurchases = billingManager.queryPurchases(BillingClient.ProductType.SUBS)
        return inAppPurchases + subPurchases
    }

    fun resetState() {
        _paymentState.value = PaymentState.Idle
    }

    fun cleanup() {
        billingManager.disconnect()
    }
}

