package com.payment.module.card

import com.payment.module.data.model.TokenizedCard
import com.payment.module.network.PaymentApiService
import com.payment.module.network.TokenizeCardRequest
import com.payment.module.security.SecureDataManager

class CardManager(
    private val apiService: PaymentApiService,
    private val secureDataManager: SecureDataManager
) {

    suspend fun tokenizeCard(
        cardNumber: String,
        expiryMonth: Int,
        expiryYear: Int,
        cvv: String,
        cardholderName: String
    ): CardResult<TokenizedCard> {
        // Validate card first
        if (!CardValidator.isValidCardNumber(cardNumber)) {
            return CardResult.Error("Invalid card number")
        }
        if (!CardValidator.isValidExpiry(expiryMonth, expiryYear)) {
            return CardResult.Error("Invalid expiry date")
        }
        if (!CardValidator.isValidCvv(cvv)) {
            return CardResult.Error("Invalid CVV")
        }

        return try {
            // Encrypt card data before sending
            val cardData = "$cardNumber|$expiryMonth|$expiryYear|$cvv|$cardholderName"
            val encryptedData = secureDataManager.encrypt(cardData)
            val nonce = secureDataManager.generateNonce()

            val response = apiService.tokenizeCard(
                TokenizeCardRequest(
                    encryptedCardData = encryptedData,
                    nonce = nonce
                )
            )

            if (response.isSuccessful && response.body() != null) {
                CardResult.Success(response.body()!!)
            } else {
                CardResult.Error("Tokenization failed")
            }
        } catch (e: Exception) {
            CardResult.Error(e.message ?: "Unknown error")
        }
    }

    suspend fun getSavedCards(): CardResult<List<TokenizedCard>> {
        return try {
            val response = apiService.getSavedCards()
            if (response.isSuccessful && response.body() != null) {
                CardResult.Success(response.body()!!)
            } else {
                CardResult.Error("Failed to fetch cards")
            }
        } catch (e: Exception) {
            CardResult.Error(e.message ?: "Unknown error")
        }
    }

    suspend fun removeCard(token: String): CardResult<Boolean> {
        return try {
            val response = apiService.removeCard(token)
            if (response.isSuccessful) {
                CardResult.Success(true)
            } else {
                CardResult.Error("Failed to remove card")
            }
        } catch (e: Exception) {
            CardResult.Error(e.message ?: "Unknown error")
        }
    }

    sealed class CardResult<out T> {
        data class Success<T>(val data: T) : CardResult<T>()
        data class Error(val message: String) : CardResult<Nothing>()
    }
}

