package com.payment.module.card

import java.util.Calendar

object CardValidator {

    fun isValidCardNumber(number: String): Boolean {
        val cleaned = number.replace("\\s".toRegex(), "")
        if (cleaned.length < 13 || cleaned.length > 19) return false
        if (!cleaned.all { it.isDigit() }) return false
        return luhnCheck(cleaned)
    }

    private fun luhnCheck(number: String): Boolean {
        var sum = 0
        var alternate = false
        for (i in number.length - 1 downTo 0) {
            var n = number[i].digitToInt()
            if (alternate) {
                n *= 2
                if (n > 9) n -= 9
            }
            sum += n
            alternate = !alternate
        }
        return sum % 10 == 0
    }

    fun isValidExpiry(month: Int, year: Int): Boolean {
        if (month < 1 || month > 12) return false
        val calendar = Calendar.getInstance()
        val currentYear = calendar.get(Calendar.YEAR) % 100
        val currentMonth = calendar.get(Calendar.MONTH) + 1
        val expYear = if (year > 100) year % 100 else year

        return when {
            expYear > currentYear -> true
            expYear == currentYear -> month >= currentMonth
            else -> false
        }
    }

    fun isValidCvv(cvv: String): Boolean {
        return cvv.length in 3..4 && cvv.all { it.isDigit() }
    }

    fun getCardBrand(number: String): String {
        val cleaned = number.replace("\\s".toRegex(), "")
        return when {
            cleaned.startsWith("4") -> "Visa"
            cleaned.matches(Regex("^5[1-5].*")) -> "Mastercard"
            cleaned.matches(Regex("^3[47].*")) -> "American Express"
            cleaned.matches(Regex("^6(?:011|5).*")) -> "Discover"
            cleaned.matches(Regex("^35(?:2[89]|[3-8][0-9]).*")) -> "JCB"
            cleaned.matches(Regex("^3(?:0[0-5]|[68]).*")) -> "Diners Club"
            else -> "Unknown"
        }
    }

    fun formatCardNumber(number: String): String {
        val cleaned = number.replace("\\s".toRegex(), "")
        val brand = getCardBrand(cleaned)
        return when (brand) {
            "American Express" -> cleaned.chunked(4).joinToString(" ").let {
                if (cleaned.length > 4) {
                    "${cleaned.take(4)} ${cleaned.drop(4).take(6)} ${cleaned.drop(10)}"
                } else it
            }
            else -> cleaned.chunked(4).joinToString(" ")
        }
    }
}

