package com.payment.module.viewmodel

import android.app.Activity
import android.app.Application
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.viewModelScope
import com.payment.module.billing.BillingManager
import com.payment.module.card.CardManager
import com.payment.module.data.model.*
import com.payment.module.network.NetworkModule
import com.payment.module.payment.PaymentProcessor
import com.payment.module.payment.PaymentState
import com.payment.module.security.DataMasker
import com.payment.module.security.IntegrityChecker
import com.payment.module.security.SecureDataManager
import com.payment.module.wallet.WalletManager
import com.payment.module.wallet.WalletResult
import kotlinx.coroutines.flow.*
import kotlinx.coroutines.launch
import java.math.BigDecimal

class PaymentViewModel(application: Application) : AndroidViewModel(application) {

    private val secureDataManager = SecureDataManager(application)
    private val integrityChecker = IntegrityChecker(application)
    private val billingManager = BillingManager(application)

    private val apiService = NetworkModule.createApiService(application) {
        secureDataManager.retrieveSecurely("auth_token")
    }

    private val walletManager = WalletManager(apiService, secureDataManager)
    private val cardManager = CardManager(apiService, secureDataManager)

    private val paymentProcessor = PaymentProcessor(
        billingManager = billingManager,
        walletManager = walletManager,
        apiService = apiService,
        secureDataManager = secureDataManager,
        integrityChecker = integrityChecker
    )

    val paymentState: StateFlow<PaymentState> = paymentProcessor.paymentState

    private val _walletBalance = MutableStateFlow<WalletBalance?>(null)
    val walletBalance: StateFlow<WalletBalance?> = _walletBalance.asStateFlow()

    private val _products = MutableStateFlow<List<Product>>(emptyList())
    val products: StateFlow<List<Product>> = _products.asStateFlow()

    private val _savedCards = MutableStateFlow<List<TokenizedCard>>(emptyList())
    val savedCards: StateFlow<List<TokenizedCard>> = _savedCards.asStateFlow()

    private val _transactionHistory = MutableStateFlow<List<Transaction>>(emptyList())
    val transactionHistory: StateFlow<List<Transaction>> = _transactionHistory.asStateFlow()

    private val _isLoading = MutableStateFlow(false)
    val isLoading: StateFlow<Boolean> = _isLoading.asStateFlow()

    private val _errorMessage = MutableStateFlow<String?>(null)
    val errorMessage: StateFlow<String?> = _errorMessage.asStateFlow()

    fun initialize() {
        viewModelScope.launch {
            _isLoading.value = true
            try {
                val connected = paymentProcessor.initialize()
                if (!connected) {
                    _errorMessage.value = "Failed to connect to billing service"
                }
            } catch (e: Exception) {
                _errorMessage.value = e.message
            } finally {
                _isLoading.value = false
            }
        }
    }

    fun setAuthToken(token: String) {
        secureDataManager.storeSecurely("auth_token", token)
    }

    fun loadProducts(productIds: List<String>) {
        viewModelScope.launch {
            _isLoading.value = true
            try {
                val productDetails = billingManager.queryProducts(productIds)
                _products.value = productDetails.map { billingManager.mapToProduct(it) }
            } catch (e: Exception) {
                _errorMessage.value = e.message
            } finally {
                _isLoading.value = false
            }
        }
    }

    fun purchaseProduct(activity: Activity, productId: String) {
        viewModelScope.launch {
            _isLoading.value = true
            try {
                val result = paymentProcessor.purchaseProduct(activity, productId)
                if (!result.success) {
                    _errorMessage.value = result.message
                }
            } catch (e: Exception) {
                _errorMessage.value = e.message
            } finally {
                _isLoading.value = false
            }
        }
    }

    fun payWithWallet(amount: BigDecimal, currency: String, description: String) {
        viewModelScope.launch {
            _isLoading.value = true
            try {
                val result = paymentProcessor.payWithWallet(amount, currency, description)
                if (result.success) {
                    fetchWalletBalance()
                } else {
                    _errorMessage.value = result.message
                }
            } catch (e: Exception) {
                _errorMessage.value = e.message
            } finally {
                _isLoading.value = false
            }
        }
    }

    fun fetchWalletBalance() {
        viewModelScope.launch {
            when (val result = walletManager.getBalance()) {
                is WalletResult.Success -> _walletBalance.value = result.data
                is WalletResult.Error -> _errorMessage.value = result.message
            }
        }
    }

    fun creditWallet(amount: BigDecimal, currency: String, source: String) {
        viewModelScope.launch {
            _isLoading.value = true
            try {
                when (val result = walletManager.creditWallet(amount, currency, source)) {
                    is WalletResult.Success -> fetchWalletBalance()
                    is WalletResult.Error -> _errorMessage.value = result.message
                }
            } finally {
                _isLoading.value = false
            }
        }
    }

    fun transferFunds(amount: BigDecimal, currency: String, recipientId: String, description: String) {
        viewModelScope.launch {
            _isLoading.value = true
            try {
                when (val result = walletManager.transferFunds(amount, currency, recipientId, description)) {
                    is WalletResult.Success -> fetchWalletBalance()
                    is WalletResult.Error -> _errorMessage.value = result.message
                }
            } finally {
                _isLoading.value = false
            }
        }
    }

    fun tokenizeCard(
        cardNumber: String,
        expiryMonth: Int,
        expiryYear: Int,
        cvv: String,
        cardholderName: String
    ) {
        viewModelScope.launch {
            _isLoading.value = true
            try {
                when (val result = cardManager.tokenizeCard(
                    cardNumber, expiryMonth, expiryYear, cvv, cardholderName
                )) {
                    is CardManager.CardResult.Success -> {
                        loadSavedCards()
                    }
                    is CardManager.CardResult.Error -> {
                        _errorMessage.value = result.message
                    }
                }
            } finally {
                _isLoading.value = false
            }
        }
    }

    fun loadSavedCards() {
        viewModelScope.launch {
            when (val result = cardManager.getSavedCards()) {
                is CardManager.CardResult.Success -> _savedCards.value = result.data
                is CardManager.CardResult.Error -> _errorMessage.value = result.message
            }
        }
    }

    fun removeCard(token: String) {
        viewModelScope.launch {
            _isLoading.value = true
            try {
                when (val result = cardManager.removeCard(token)) {
                    is CardManager.CardResult.Success -> loadSavedCards()
                    is CardManager.CardResult.Error -> _errorMessage.value = result.message
                }
            } finally {
                _isLoading.value = false
            }
        }
    }

    fun requestRefund(transactionId: String, reason: String, amount: BigDecimal? = null) {
        viewModelScope.launch {
            _isLoading.value = true
            try {
                val result = paymentProcessor.requestRefund(transactionId, reason, amount)
                if (!result.success) {
                    _errorMessage.value = result.message
                }
            } finally {
                _isLoading.value = false
            }
        }
    }

    fun loadTransactionHistory(page: Int = 1) {
        viewModelScope.launch {
            _isLoading.value = true
            try {
                when (val result = walletManager.getTransactionHistory(page)) {
                    is WalletResult.Success -> {
                        _transactionHistory.value = result.data.transactions
                    }
                    is WalletResult.Error -> _errorMessage.value = result.message
                }
            } finally {
                _isLoading.value = false
            }
        }
    }

    fun restorePurchases() {
        viewModelScope.launch {
            _isLoading.value = true
            try {
                val purchases = paymentProcessor.restorePurchases()
                // Handle restored purchases
                for (purchase in purchases) {
                    // Verify each purchase with server
                }
            } catch (e: Exception) {
                _errorMessage.value = e.message
            } finally {
                _isLoading.value = false
            }
        }
    }

    fun getSecurityStatus(): IntegrityChecker.SecurityCheckResult {
        return integrityChecker.isDeviceSecure()
    }

    fun maskCardNumber(cardNumber: String): String = DataMasker.maskCardNumber(cardNumber)
    fun maskEmail(email: String): String = DataMasker.maskEmail(email)

    fun clearError() {
        _errorMessage.value = null
    }

    fun resetPaymentState() {
        paymentProcessor.resetState()
    }

    override fun onCleared() {
        super.onCleared()
        paymentProcessor.cleanup()
    }
}

